import { Injectable } from '@angular/core';
import { initializeApp } from 'firebase/app';
import { getFirestore, collection, addDoc, doc, setDoc } from 'firebase/firestore';
import { Team, User } from '../models';

// IMPORTANT: In a real app, this config would be in a secure environment file.
const firebaseConfig = {
  apiKey: "YOUR_API_KEY",
  authDomain: "YOUR_AUTH_DOMAIN",
  projectId: "YOUR_PROJECT_ID",
  storageBucket: "YOUR_STORAGE_BUCKET",
  messagingSenderId: "YOUR_MESSAGING_SENDER_ID",
  appId: "YOUR_APP_ID"
};

@Injectable({
  providedIn: 'root'
})
export class FirebaseService {
  private app = initializeApp(firebaseConfig);
  private db = getFirestore(this.app);

  constructor() { }

  // Function to save a new team and user
  async saveTeamOwner(team: Team, user: User) {
    try {
      // Save the team document
      await setDoc(doc(this.db, "teams", team.id.toString()), {
        name: team.name,
        owner: team.owner,
        captainRole: team.captainRole,
        color: team.color,
        logo: team.logo
      });

      // Save the user document
      await setDoc(doc(this.db, "users", user.id.toString()), {
        username: user.username,
        // In a real app, you'd use Firebase Authentication, not save passwords.
        role: user.role,
        teamId: user.teamId
      });

      console.log("Team and Owner saved successfully to Firestore!");

    } catch (e) {
      console.error("Error adding document: ", e);
    }
  }
}
